#!/usr/bin/env python3
import os, base64, re

files = [
  ('lib\\\\sync\\\\engine.ts', ''),
  ('app\\\\api\\\\cron\\\\master-sync\\\\route.ts', ''),
  ('app\\\\api\\\\integrations\\\\personalkollen\\\\route.ts', ''),
  ('app\\\\api\\\\integrations\\\\generic\\\\route.ts', ''),
  ('app\\\\integrations\\\\page.tsx', ''),
]

for win_path, b64 in files:
    import re as _re
    path = win_path.replace("\\\\", os.sep).replace("\\", os.sep)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    content = base64.b64decode(b64).decode("utf-8")
    content = _re.sub(r"as const(\s+as const)+", "as const", content)
    with open(path, "wb") as f:
        f.write(content.encode("utf-8"))
    print(f"Written: {path}")
print("\nDone — git add . && git commit -m \"Multi-business isolation for APIs\" && vercel --prod")
